import sys

class QueryToken:
    def __init__(self, raw):
        self.raw = raw

    def pair(self):
        if '=' not in self.raw:
            return self.raw, ''
        key, value = self.raw.split('=', 1)
        return key, value

class QueryStringParser:
    def __init__(self, url):
        self.url = url

    def query(self):
        if '?' not in self.url:
            return ''
        return self.url.split('?', 1)[1]

    def values(self):
        parsed = {}
        for token in self.query().split('&'):
            if not token:
                continue
            key, value = QueryToken(token).pair()
            parsed[key] = value
        return parsed

parser = QueryStringParser(sys.argv[1])
print(parser.values().get(sys.argv[2], ''))

import sys

class AmountRow:
    def __init__(self, raw):
        parts = raw.split(',')
        self.name = parts[0]
        self.amount = int(parts[1])

class AmountLedger:
    def __init__(self, text):
        self.rows = []
        for line in text.splitlines():
            if line.strip():
                self.rows.append(AmountRow(line.strip()))

    def sum_for(self, name):
        total = 0
        for row in self.rows:
            if row.name == name:
                total += row.amount
        return total

ledger = AmountLedger(sys.argv[1])
print(ledger.sum_for(sys.argv[2]))

import sys

class IntegerBoundary:
    def __init__(self, low, high):
        self.low = low
        self.high = high

    def contains(self, value):
        return self.low <= value <= self.high

class PortNormalizer:
    def __init__(self):
        self.boundary = IntegerBoundary(0, 65535)

    def normalize(self, value):
        number = int(value)
        if self.boundary.contains(number):
            return number
        if number < self.boundary.low:
            return self.boundary.low
        return self.boundary.high

print(PortNormalizer().normalize(sys.argv[1]))
